INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('Football', 'The world''s most popular sport played in over 200 countries.', 'Brazil has won the FIFA World Cup a record 5 times.', '⚽', 'football', 'Football is the most popular sport on the planet with an estimated 4 billion fans worldwide, making it truly a global phenomenon that transcends cultures and borders.', 'The first official international football match was played in 1872 between Scotland and England in Glasgow, ending in a 0-0 draw watched by around 4,000 spectators.', 'FIFA, the governing body of world football, was founded in Paris on May 21, 1904, and today has 211 member associations, more than the United Nations.', 'The FIFA World Cup is the most watched sporting event in the world, with the 2022 Qatar World Cup final between Argentina and France attracting over 1.5 billion viewers globally.', 'Lionel Messi is widely considered the greatest footballer of all time, winning 8 Ballon d''Or awards and leading Argentina to the 2022 World Cup title in what many called the greatest final ever played.', 'Cristiano Ronaldo became the first player in history to score over 900 career goals across club and international football, cementing his legacy as one of the sport''s all time greats.', 'The UEFA Champions League is the most prestigious club competition in the world, with Real Madrid holding the record for the most titles with 15 European Cups throughout their illustrious history.', 'The English Premier League is the most watched football league in the world, broadcast to over 880 million homes in 188 countries and generating billions in revenue every single season.', 'Brazil is the most successful nation in World Cup history, having won the tournament five times in 1958, 1962, 1970, 1994 and 2002, and they are the only team to have played in every World Cup.', 'The offside rule, one of football''s most debated laws, was first introduced in 1863 and has evolved significantly over the decades, with VAR technology now helping referees make more accurate decisions.', 'https://images.unsplash.com/photo-1579952363873-27f3bade9f55?w=800', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('Basketball', 'Born in 1891, now one of the biggest sports on the planet with hundreds of millions of fans worldwide.', 'The NBA is the most prestigious basketball league in the world.', '🏀', 'basketball', 'Basketball was invented in December 1891 by Canadian-American physical education instructor Dr. James Naismith, who created the game to keep his students active during the cold winter months in Massachusetts.', 'The original basketball game used a soccer ball and two peach baskets as goals, with a janitor having to retrieve the ball from the basket every time someone scored a point.', 'The NBA was founded in 1946 as the Basketball Association of America and merged with the National Basketball League in 1949 to form the National Basketball Association we know today.', 'Michael Jordan is widely regarded as the greatest basketball player of all time, winning 6 NBA Championships, 6 Finals MVP awards and 5 regular season MVP awards during his legendary career with the Chicago Bulls.', 'LeBron James became the NBA all time leading scorer in 2023, surpassing Kareem Abdul-Jabbar''s record of 38,387 points that had stood for nearly 40 years, while also winning 4 NBA Championships.', 'The Boston Celtics are the most successful franchise in NBA history with 18 championships, ahead of the Los Angeles Lakers who have won 17 titles, making their rivalry one of the greatest in all of sports.', 'Wilt Chamberlain scored an incredible 100 points in a single NBA game on March 2, 1962, playing for the Philadelphia Warriors against the New York Knicks, a record that still stands today and may never be broken.', 'Basketball became an Olympic sport for men at the 1936 Berlin Games, with the United States winning the first gold medal. The USA has dominated Olympic basketball, winning gold at almost every Games since then.', 'Nikola Jokic of the Denver Nuggets became the first center to win three MVP awards in the modern NBA era, and led his team to their first ever NBA Championship in 2023 with one of the greatest individual performances in Finals history.', 'Stephen Curry revolutionized basketball with his extraordinary three point shooting ability, breaking the NBA record for three pointers made in a season multiple times and inspiring a generation of players to shoot from beyond the arc.', '/images/basketball.jpg', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('Formula 1', 'The pinnacle of motorsport combining cutting edge technology, incredible speed and elite driver skill at circuits around the world.', 'Michael Schumacher and Lewis Hamilton both won 7 World Championships.', '🏎️', 'formula1', 'The Formula 1 World Championship began in 1950 with the first race held at Silverstone in England, won by Italian driver Giuseppe Farina who became the first ever Formula 1 World Champion.', 'Formula 1 cars are engineering masterpieces that can accelerate from 0 to 100 km/h in under 2.5 seconds, reach top speeds of over 370 km/h, and generate enough downforce to drive upside down on a ceiling.', 'Michael Schumacher dominated Formula 1 in the early 2000s, winning five consecutive World Championships from 2000 to 2004 with Ferrari, a record that stood until Lewis Hamilton matched his total of seven titles.', 'Lewis Hamilton is the most decorated driver in Formula 1 history, winning seven World Championships and holding records for most wins, most pole positions and most podium finishes in the sport''s history.', 'Ferrari is the oldest and most iconic team in Formula 1, having competed in every season since the championship began in 1950, and holding the record for the most constructor championships in the sport''s history.', 'The Monaco Grand Prix held on the streets of Monte Carlo is the most glamorous and prestigious race in Formula 1, known for its narrow streets, tight corners and the incredible skill required to navigate the circuit at racing speeds.', 'Max Verstappen became the most dominant Formula 1 champion of his era, winning four consecutive World Championships from 2021 to 2024 with Red Bull Racing, including a record 19 wins in a single season in 2023.', 'Formula 1 cars use Pirelli tires that can reach temperatures of up to 120 degrees Celsius during a race, and drivers must carefully manage their tire strategy throughout the race to achieve the best possible result.', 'The Drivers'' World Championship is decided by a points system where drivers earn points for finishing in the top ten positions, with 25 points awarded for a race win and one point for the fastest lap of the race.', 'Formula 1 is one of the most expensive sports in the world, with top teams spending hundreds of millions of dollars per season on car development, driver salaries and logistics to compete at races around the globe.', '/images/formula1.jpg', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('Tennis', 'One of the most elegant and physically demanding individual sports in the world, played in over 200 countries.', 'Novak Djokovic holds the record for most Grand Slam titles with 24.', '🎾', 'tennis', 'Tennis has ancient origins dating back to 12th century France where players would hit a ball with the palm of their hand, evolving over centuries into the racket sport we know and love today.', 'Wimbledon, held at the All England Club in London, is the oldest and most prestigious tennis tournament in the world, first held in 1877, and is famous for its strict all white dress code and tradition of strawberries and cream.', 'The four Grand Slam tournaments are the Australian Open, French Open, Wimbledon and US Open, and winning all four in a single calendar year is known as the Grand Slam, one of the rarest achievements in all of sport.', 'Novak Djokovic is the greatest tennis player of all time by Grand Slam titles, having won 24 major championships and completing his career Golden Slam by winning Olympic gold at the Paris 2024 Games.', 'Rafael Nadal is the undisputed King of Clay, having won the French Open at Roland Garros an incredible 14 times throughout his legendary career, a record that many experts believe will never be beaten.', 'Roger Federer is considered one of the most elegant and technically gifted players in tennis history, winning 20 Grand Slam titles and spending a record 310 weeks as the world number one player during his career.', 'The Williams sisters, Venus and Serena, revolutionized women''s tennis with their powerful playing style, with Serena winning 23 Grand Slam singles titles and Venus winning 7, dominating the sport for over two decades.', 'Carlos Alcaraz became one of the youngest players to win multiple Grand Slam titles, claiming four major championships before the age of 22 including back to back Wimbledon titles, establishing himself as the future of tennis.', 'Jannik Sinner rose to become the world number one ranked player in 2024, winning the Australian Open and US Open in the same year and establishing himself as one of the most dominant players on the tour.', 'Tennis balls must be pressurized and are changed every nine games during professional matches, as the felt covering wears down and the ball loses its bounce, significantly affecting the speed and character of play.', 'https://images.unsplash.com/photo-1554068865-24cecd4e34b8?w=800', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('NFL', 'American Football is one of the most watched and physically intense team sports in the world, deeply embedded in American culture.', 'The Super Bowl is the most watched TV event in American history.', '🏈', 'nfl', 'American Football evolved from rugby and soccer in the late 19th century, with the first college football game played between Rutgers and Princeton in 1869, marking the beginning of what would become America''s most popular sport.', 'The NFL was founded in 1920 as the American Professional Football Association with just 14 teams, growing into a multi-billion dollar league with 32 franchises that generates over 18 billion dollars in revenue every single season.', 'The Super Bowl is the most watched television event in American history, regularly attracting over 100 million viewers in the United States alone, with the halftime show becoming one of the most anticipated musical performances of the year.', 'Tom Brady is considered the greatest NFL player of all time, winning 7 Super Bowl championships with three different teams across his 23 year career, throwing for over 89,000 passing yards and 649 touchdowns.', 'Patrick Mahomes has established himself as the best quarterback of his generation, leading the Kansas City Chiefs to three Super Bowl victories and winning multiple MVP awards before the age of 30, cementing his place among the all time greats.', 'An NFL football game consists of four 15 minute quarters, but due to stoppages in play, timeouts and commercial breaks, a typical game lasts approximately three hours, with teams playing 17 regular season games per year.', 'The NFL Draft is one of the most anticipated events in American sports, where teams select college players in reverse order of their previous season finish, giving weaker teams the opportunity to improve by picking the best young talent available.', 'Jerry Rice is widely considered the greatest wide receiver in NFL history, holding records for career receptions, receiving yards and receiving touchdowns, winning three Super Bowls with the San Francisco 49ers during his legendary career.', 'Lawrence Taylor revolutionized the linebacker position with his explosive speed and pass rushing ability, winning two Super Bowls with the New York Giants and being named the greatest defensive player in NFL history by many experts.', 'The Kansas City Chiefs have become a dynasty in modern NFL history, appearing in five Super Bowls in just six years under the leadership of quarterback Patrick Mahomes and head coach Andy Reid, winning three of those championship games.', '/images/nfl.jpg', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('MMA & UFC', 'Mixed Martial Arts is the fastest growing sport in the world, combining techniques from multiple disciplines into one complete fighting system.', 'The UFC has grown from a niche event into a global sports phenomenon worth billions of dollars.', '🥊', 'mma', 'Mixed Martial Arts combines techniques from boxing, wrestling, Brazilian jiu-jitsu, Muay Thai, judo and many other martial arts disciplines into one complete fighting system that tests every aspect of a fighter''s athletic ability.', 'The UFC was founded in 1993 originally as a tournament to determine which martial art was most effective in real combat, with no weight classes and very few rules, evolving dramatically over the decades into the highly regulated sport it is today.', 'Ilia Topuria made history in February 2024 by knocking out Alexander Volkanovski in the second round to become UFC Featherweight Champion, then moved up in weight and knocked out Dustin Poirier to become a two division champion.', 'Merab Dvalishvili became UFC Bantamweight Champion in 2024, meaning Georgia became the only country in the world to simultaneously hold two UFC championship titles, an incredible achievement for such a small nation.', 'Khabib Nurmagomedov retired from MMA with a perfect 29-0 record, never losing a single professional fight, and is widely considered the most dominant UFC Lightweight Champion in the history of the sport.', 'Jon Jones is considered by many experts to be the greatest UFC fighter of all time, winning championships in two different weight classes and remaining undefeated in title fights throughout his extraordinary career spanning over 15 years.', 'Conor McGregor became the first fighter in UFC history to hold championships in two different weight classes simultaneously, and his fights against Khabib Nurmagomedov and Nate Diaz broke pay-per-view records around the world.', 'UFC fighters train in multiple disciplines simultaneously, typically spending hours every day working on their striking, wrestling, grappling and conditioning to ensure they can compete effectively in all areas of mixed martial arts competition.', 'The UFC now holds events in over 40 countries around the world, with fighters from every continent competing for championships, demonstrating how truly global mixed martial arts has become since its humble beginnings in the early 1990s.', 'Islam Makhachev succeeded his mentor Khabib Nurmagomedov as UFC Lightweight Champion and rose to become the pound for pound number one fighter in the world, continuing the incredible legacy of Dagestani fighters in the sport.', '/images/mma.jpg', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('Rugby', 'A full contact team sport that demands extraordinary physical strength, endurance and teamwork, played in over 120 countries worldwide.', 'Rugby is one of the fastest growing sports in the world with a passionate global following.', '🏉', 'rugby', 'Rugby was invented in 1823 according to popular legend when William Webb Ellis, a student at Rugby School in England, picked up the ball during a football game and ran with it, creating an entirely new sport in that moment.', 'The Rugby World Cup is held every four years and is the third largest sporting event in the world by viewership, behind only the FIFA World Cup and the Olympic Games, attracting hundreds of millions of viewers globally.', 'South Africa''s Springboks are the most successful team in Rugby World Cup history, having won the tournament four times in 1995, 2007, 2019 and 2023, with Siya Kolisi becoming the first Black captain to lift the trophy in 2019.', 'The New Zealand All Blacks are the most iconic team in rugby history, known for performing the Haka before every match, winning three Rugby World Cups and maintaining the highest win percentage of any international sports team in history.', 'Georgia''s national rugby team, nicknamed the Lelos, has qualified for every Rugby World Cup since 2003 and is consistently ranked among the top 12 teams in the world, with their powerful scrum being one of their greatest strengths.', 'Antoine Dupont of France is considered the best rugby player in the world, winning the World Player of the Year award and leading France to Olympic gold in Rugby Sevens at the Paris 2024 Games in front of a passionate home crowd.', 'Rugby union is played with 15 players per side in two 40 minute halves, while rugby sevens is played with only 7 players per side in shorter games, with the sevens format becoming increasingly popular after its inclusion in the Olympics.', 'The scrum is one of rugby''s most distinctive features, where eight players from each team bind together and push against each other to contest possession of the ball, requiring enormous physical strength, technique and coordination.', 'Richie McCaw of New Zealand is considered the greatest rugby player of all time, captaining the All Blacks to back to back Rugby World Cup victories in 2011 and 2015 and winning the World Player of the Year award three times.', 'Rugby''s values of teamwork, respect, enjoyment, discipline and sportsmanship are central to the culture of the sport, with players from opposing teams traditionally sharing a meal and drinks together after every match regardless of the result.', '/images/rugby.jpg', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('Olympics', 'The greatest multi-sport event on Earth, bringing together thousands of athletes from every nation to compete for glory every four years.', 'The Olympics represent the pinnacle of athletic achievement for competitors from around the world.', '🏅', 'olympics', 'The ancient Olympic Games began in 776 BC in Olympia, Greece, held in honor of the god Zeus, and were contested every four years for nearly 1,200 years before being abolished by the Roman Emperor Theodosius in 393 AD.', 'The modern Olympic Games were revived by Pierre de Coubertin and first held in Athens, Greece in 1896 with 241 athletes from 14 nations competing in 43 events, compared to the thousands of athletes who compete today.', 'Michael Phelps of the United States is the most decorated Olympian of all time, winning an astonishing 23 gold medals and 28 total medals across four Olympic Games in swimming, a record that may stand forever.', 'Simone Biles is considered the greatest gymnast of all time, winning 7 Olympic medals and 30 World Championship medals, performing skills so difficult that several have been named after her in the official gymnastics code of points.', 'Usain Bolt of Jamaica is the fastest human being ever recorded, winning three consecutive 100m and 200m Olympic gold medals and setting world records of 9.58 seconds for the 100m and 19.19 seconds for the 200m that still stand today.', 'Georgia first competed as an independent nation at the 1996 Atlanta Olympics and has since won medals in wrestling, judo and weightlifting, with Lasha Talakhadze winning back to back gold medals in weightlifting while breaking multiple world records.', 'The Olympic motto is Citius, Altius, Fortius which is Latin for Faster, Higher, Stronger, with the word Communiter meaning Together added in 2021 to reflect the importance of solidarity and community in the Olympic movement.', 'The Olympic flame is lit in Olympia, Greece using the sun''s rays and a parabolic mirror, and is then carried by thousands of torchbearers in a relay across the host country before being used to light the cauldron at the opening ceremony.', 'The 2024 Paris Olympics were considered one of the most spectacular in history, with iconic Parisian landmarks serving as venues and the opening ceremony held on the River Seine, attracting billions of viewers around the world.', 'The next Summer Olympics will be held in Los Angeles in 2028, followed by Brisbane in 2032, with the Games continuing to grow in size and spectacle as more sports and athletes from around the world participate in the greatest sporting event on Earth.', '/images/olympics.jpg', '', '');
INSERT INTO sport (name, description, fact, emoji, url_name, fact1, fact2, fact3, fact4, fact5, fact6, fact7, fact8, fact9, fact10, image_url, athlete_image_url, athlete_name) VALUES ('World Cup 2026', 'The FIFA World Cup 2026 will be the largest and most spectacular World Cup in history, hosted across three nations with 48 teams competing.', 'The 2026 World Cup will be the first ever with 48 teams competing.', '🏆', 'worldcup2026', 'The 2026 FIFA World Cup will be jointly hosted by the United States, Canada and Mexico, making it the first World Cup ever to be hosted across three different countries and the second time Mexico has hosted the tournament.', 'For the first time in World Cup history, 48 national teams will compete in the 2026 tournament instead of the usual 32, giving more nations from around the world the opportunity to compete on the biggest stage in football.', 'The tournament will feature 104 matches in total, played across 16 different stadiums in 11 American cities, 3 Canadian cities and 3 Mexican cities, with the grand final to be held at MetLife Stadium in New Jersey.', 'Argentina enter the 2026 World Cup as reigning champions after their extraordinary triumph at the 2022 Qatar World Cup, where they defeated France in one of the greatest finals ever played, with Lionel Messi finally claiming the one trophy that had eluded him.', 'France will be among the strongest contenders in 2026 with a golden generation of players including Kylian Mbappe, who is determined to go one better than the 2022 final where France came agonizingly close to becoming back to back world champions.', 'Brazil, the most successful nation in World Cup history with five titles, will be desperate to end a 24 year wait for a sixth World Cup trophy, with Vinicius Junior leading a talented generation of Brazilian players hungry for glory.', 'England have never won the World Cup since their famous victory on home soil in 1966, but with stars like Harry Kane, Jude Bellingham and Bukayo Saka, they will be considered genuine contenders for the 2026 title.', 'Spain enter 2026 as European Champions after winning Euro 2024 in dominant fashion, with a young and talented squad built around Carlos Alcaraz''s brother Pedri, Lamine Yamal and a core of technically gifted players.', 'The expanded 48 team format means that smaller football nations will have more opportunity to qualify, potentially allowing teams from Asia, Africa and North America to make deeper runs in the tournament than ever before.', 'The 2026 World Cup final will be played on July 19, 2026 at MetLife Stadium in New Jersey, which has a capacity of over 82,000 and will host what promises to be the most watched sporting event in human history.', '/images/worldcup.jpg', '', '');
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Khvicha Kvaratskhelia', 'Football', 'Georgian', 'Known as Kvaradona, Khvicha is Georgia''s greatest ever footballer. He rose to fame at Napoli winning Serie A and moved to PSG in 2025.', 'Serie A Champion 2023, UEFA Euro 2024 participant', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Giorgi Mamardashvili', 'Football', 'Georgian', 'World class goalkeeper signed by Liverpool FC. Considered one of the best goalkeepers in Europe after stunning performances at Valencia and Euro 2024.', 'Signed by Liverpool FC, Euro 2024 standout performer', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Giorgi Chakvetadze', 'Football', 'Georgian', 'Creative midfielder who plays in Europe and is a key member of the Georgian national team. Known for his technical ability and vision.', 'Key Georgian national team midfielder', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Otar Kiteishvili', 'Football', 'Georgian', 'Talented Georgian midfielder playing in the Bundesliga. A crucial part of Georgia''s historic Euro 2024 campaign.', 'Bundesliga player, Euro 2024 hero', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Zuriko Davitashvili', 'Football', 'Georgian', 'Fast and tricky winger who plays in Ligue 1. One of Georgia''s most exciting attacking players with pace and skill to beat any defender.', 'Ligue 1 player, Georgian national team star', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lionel Messi', 'Football', 'Argentine', 'Widely considered the greatest footballer of all time. Won 8 Ballon d''Or awards and led Argentina to the 2022 World Cup title.', '8x Ballon d''Or, 2022 World Cup Winner, Copa America 2021', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Cristiano Ronaldo', 'Football', 'Portuguese', 'One of the greatest footballers ever with over 900 career goals. Won 5 Ballon d''Or awards and 5 Champions League titles.', '5x Ballon d''Or, 5x Champions League Winner', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Kylian Mbappé', 'Football', 'French', 'The fastest player in the world and France''s biggest star. Won the World Cup at just 19 years old and joined Real Madrid in 2024.', '2018 World Cup Winner, signed by Real Madrid 2024', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Erling Haaland', 'Football', 'Norwegian', 'The most deadly striker in the world. Scored 36 Premier League goals in his debut season at Manchester City, breaking all records.', 'Premier League record 36 goals in one season', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jude Bellingham', 'Football', 'English', 'England''s biggest star and one of the best midfielders in the world. Joined Real Madrid in 2023 and won La Liga in his first season.', 'La Liga Winner 2024 with Real Madrid', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Kevin De Bruyne', 'Football', 'Belgian', 'The best playmaker of his generation. Has won 6 Premier League titles with Manchester City and is known for his incredible passing.', '6x Premier League Winner, Champions League 2023', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Vinícius Júnior', 'Football', 'Brazilian', 'One of the most exciting wingers in the world. Won the Ballon d''Or in 2024 and is the heart of Real Madrid''s attack.', 'Ballon d''Or 2024, 2x Champions League Winner', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Rodri', 'Football', 'Spanish', 'The best defensive midfielder in the world. Won the Ballon d''Or in 2023 and led Spain to Euro 2024 glory.', 'Ballon d''Or 2023, Euro 2024 Winner', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Mohamed Salah', 'Football', 'Egyptian', 'Liverpool''s legendary Egyptian King. One of the most prolific scorers in Premier League history with incredible speed and finishing.', '2x Premier League Golden Boot, Champions League Winner 2019', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Harry Kane', 'Football', 'English', 'England''s all time top scorer and one of the best strikers in the world. Joined Bayern Munich in 2023 and broke the Bundesliga scoring record.', 'England all time top scorer, Bundesliga record scorer', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alphonso Davies', 'Football', 'Canadian', 'Alphonso Davies is one of the most exciting left backs in the world, playing for FC Bayern Munich. Born in a refugee camp in Ghana to Liberian parents, Davies and his family moved to Canada where he rose to become one of football''s brightest stars. At the 2024 FIFA World Cup Summit, Davies gave a powerful speech about the importance of the 2026 World Cup being hosted in North America, saying it would inspire millions of young players across Canada, USA and Mexico to dream bigger. He spoke about his own journey from refugee camps to the Champions League, proving that football truly has the power to change lives.', 'UEFA Champions League Winner, Bundesliga Champion, Canadian Player of the Year', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Kevin Durant', 'Basketball', 'American', 'One of the most skilled scorers in NBA history. Won 2 NBA championships and 2 Finals MVP awards with the Golden State Warriors.', '2x NBA Champion, 2x Finals MVP', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('LeBron James', 'Basketball', 'American', 'The greatest basketball player of his generation. Won 4 NBA championships with 3 different teams and is the NBA all time leading scorer.', 'NBA All Time Leading Scorer, 4x NBA Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Stephen Curry', 'Basketball', 'American', 'The greatest shooter in NBA history. Revolutionized basketball with his three point shooting and won 4 NBA titles with the Golden State Warriors.', '4x NBA Champion, 2x MVP, Greatest Shooter Ever', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Nikola Jokić', 'Basketball', 'Serbian', 'The most dominant center in modern basketball. Won 3 MVP awards and led Denver Nuggets to their first ever NBA Championship in 2023.', '3x MVP, NBA Champion 2023', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Giannis Antetokounmpo', 'Basketball', 'Greek', 'The Greek Freak. Won 2 MVP awards and led the Milwaukee Bucks to the NBA Championship in 2021 with a legendary Finals performance.', '2x MVP, NBA Champion 2021', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Luka Dončić', 'Basketball', 'Slovenian', 'The best young player in the NBA. Led Dallas Mavericks to the NBA Finals in 2024 and is considered the future of basketball.', 'NBA Finals 2024, EuroLeague Champion at 18', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jayson Tatum', 'Basketball', 'American', 'Boston Celtics superstar who led his team to the NBA Championship in 2024. Known for his clutch scoring and two way play.', 'NBA Champion 2024 with Boston Celtics', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Joel Embiid', 'Basketball', 'Cameroonian', 'One of the most dominant centers in the NBA. Won the MVP award in 2023 and is known for his unstoppable scoring ability.', 'NBA MVP 2023', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Kawhi Leonard', 'Basketball', 'American', 'One of the best two way players in NBA history. Won NBA Championships with two different teams and is known as The Klaw.', '2x NBA Champion, 2x Finals MVP', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Anthony Davis', 'Basketball', 'American', 'One of the most dominant big men in the NBA. Won the NBA Championship with the LA Lakers in 2020 alongside LeBron James.', 'NBA Champion 2020, 8x All Star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Devin Booker', 'Basketball', 'American', 'Phoenix Suns superstar and one of the best scorers in the NBA. Won Olympic gold with Team USA at the Paris 2024 Olympics.', 'Olympic Gold 2024, NBA All Star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Shai Gilgeous-Alexander', 'Basketball', 'Canadian', 'Oklahoma City Thunder star and one of the most unstoppable scorers in the NBA. Led OKC to the best record in the league in 2024.', 'NBA scoring leader, All Star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jimmy Butler', 'Basketball', 'American', 'One of the most competitive players in the NBA. Led the Miami Heat to two NBA Finals and is known for his incredible clutch performances.', '2x NBA Finals, 6x All Star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Damian Lillard', 'Basketball', 'American', 'One of the greatest point guards of his generation. Known for his incredible clutch shooting and joined the Milwaukee Bucks in 2023.', '7x All Star, clutch shooting legend', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Ja Morant', 'Basketball', 'American', 'Memphis Grizzlies electrifying point guard. Known for his incredible athleticism and highlight reel dunks. One of the most exciting players in the NBA.', 'NBA Most Improved Player 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lewis Hamilton', 'Formula 1', 'British', 'The most decorated Formula 1 driver in history. Won 7 World Championships tying Michael Schumacher''s record and joined Ferrari in 2025.', '7x Formula 1 World Champion, Joined Ferrari 2025', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Max Verstappen', 'Formula 1', 'Dutch', 'The most dominant Formula 1 driver of his era. Won 4 consecutive World Championships with Red Bull Racing from 2021 to 2024.', '4x Formula 1 World Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Charles Leclerc', 'Formula 1', 'Monegasque', 'Ferrari''s star driver and one of the fastest qualifiers on the grid. Known for his incredible one lap pace and passionate racing style.', 'Multiple F1 race wins with Ferrari', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lando Norris', 'Formula 1', 'British', 'McLaren''s rising star and one of the most popular drivers on the grid. Won his first Formula 1 race in 2024 and is challenging for the championship.', 'First F1 win 2024, McLaren lead driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Novak Djokovic', 'Tennis', 'Serbian', 'The greatest tennis player of all time by Grand Slam titles. Won 24 Grand Slams and Olympic gold at Paris 2024 completing his career golden slam.', '24x Grand Slam Winner, Olympic Gold 2024', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Carlos Alcaraz', 'Tennis', 'Spanish', 'The future of tennis and one of the most exciting players ever. Won 4 Grand Slam titles before turning 22 including back to back Wimbledon titles.', '4x Grand Slam Winner, 2x Wimbledon Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jannik Sinner', 'Tennis', 'Italian', 'World number one and the best player in the world in 2024. Won the Australian Open and US Open in 2024 to establish himself as the top player.', 'World No.1, 2x Grand Slam Winner 2024', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Tom Brady', 'NFL', 'American', 'The greatest NFL player of all time. Won 7 Super Bowl championships with 3 different teams and retired as the greatest quarterback ever.', '7x Super Bowl Champion, Greatest QB Ever', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Patrick Mahomes', 'NFL', 'American', 'The best quarterback in the NFL today. Led the Kansas City Chiefs to 3 Super Bowl victories and is considered the heir to Tom Brady''s legacy.', '3x Super Bowl Champion, 2x NFL MVP', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Josh Allen', 'NFL', 'American', 'Buffalo Bills superstar quarterback and one of the most exciting players in the NFL. Known for his powerful arm and incredible athleticism.', 'NFL MVP candidate, Pro Bowl selection', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Joe Burrow', 'NFL', 'American', 'Cincinnati Bengals franchise quarterback who led his team to the Super Bowl in 2022. Known for his cool demeanor and pinpoint accuracy.', 'Super Bowl LVI appearance, AFC Champion 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Ilia Topuria', 'MMA & UFC', 'Georgian', 'Ilia Topuria is one of the most exciting fighters in UFC history and a national hero in Georgia. Born in Georgia and raised in Spain, he became UFC Featherweight Champion in February 2024 by knocking out Alexander Volkanovski in the second round. He then moved up to Lightweight and knocked out Dustin Poirier to become a two division UFC champion, one of the rarest achievements in MMA history. Topuria is known for his incredible knockout power, unbeaten record and passionate love for Georgia.', 'UFC Featherweight Champion, UFC Lightweight Champion, Two Division Champion', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Merab Dvalishvili', 'MMA & UFC', 'Georgian', 'Merab Dvalishvili is the UFC Bantamweight Champion and one of the most exciting fighters in the world. Known as The Machine for his relentless wrestling and incredible cardio, Merab became champion in 2024 making Georgia the only country to simultaneously hold two UFC titles. Born in Tbilisi, Georgia, Merab is a symbol of Georgian toughness and determination, beloved by fans around the world for his never give up fighting style.', 'UFC Bantamweight Champion, Georgian national hero', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jon Jones', 'MMA & UFC', 'American', 'Considered the greatest UFC fighter of all time. Won championships in two weight classes and has never lost a fight by decision or finish in his career.', 'UFC Light Heavyweight and Heavyweight Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Khabib Nurmagomedov', 'MMA & UFC', 'Russian', 'Retired undefeated with a 29-0 record. The most dominant UFC Lightweight Champion in history who suffocated every opponent with his wrestling.', 'UFC Lightweight Champion, 29-0 undefeated', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Islam Makhachev', 'MMA & UFC', 'Russian', 'Current UFC Lightweight Champion and pound for pound number one fighter in the world. Trained by Khabib and is considered his successor.', 'UFC Lightweight Champion, P4P #1', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Conor McGregor', 'MMA & UFC', 'Irish', 'The biggest star in MMA history. Won championships in two weight classes simultaneously and brought UFC to a global mainstream audience.', '2x UFC Champion, Biggest MMA star ever', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Antoine Dupont', 'Rugby', 'French', 'The best rugby player in the world. Won the Rugby World Player of the Year award and led France to Olympic gold in Rugby Sevens at Paris 2024.', 'World Player of the Year, Olympic Gold 2024', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Siya Kolisi', 'Rugby', 'South African', 'South Africa''s inspirational captain who led the Springboks to back to back Rugby World Cup victories in 2019 and 2023.', '2x Rugby World Cup Winner as Captain', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Richie McCaw', 'Rugby', 'New Zealander', 'The greatest rugby player of all time. Led the All Blacks to back to back Rugby World Cup victories in 2011 and 2015 and won 3 World Player of the Year awards.', '2x Rugby World Cup Winner, 3x World Player of Year', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Michael Phelps', 'Olympics', 'American', 'The most decorated Olympian of all time with 23 gold medals. Dominated swimming for over a decade and is considered the greatest Olympian ever.', '23 Olympic Gold Medals, 28 total medals', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Larisa Latynina', 'Olympics', 'Soviet', 'The most decorated female Olympian in history until Michael Phelps broke her record. Won 9 gold medals in gymnastics across three Olympic Games.', '9 Olympic Gold Medals in Gymnastics', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Simone Biles', 'Olympics', 'American', 'The greatest gymnast of all time. Won 7 Olympic medals including 4 gold and is the most decorated American gymnast in history.', '7 Olympic Medals, Greatest Gymnast Ever', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lasha Talakhadze', 'Olympics', 'Georgian', 'Georgia''s greatest ever Olympian. Won back to back Olympic gold medals in weightlifting while breaking world records at both Rio 2016 and Tokyo 2020.', '2x Olympic Gold, Multiple World Records', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Argentina', 'World Cup 2026', 'Argentine', 'Reigning World Champions led by Lionel Messi. Argentina will look to defend their 2022 title and become the first back to back champions since Brazil in 1958 and 1962.', 'Reigning World Champions 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('France', 'World Cup 2026', 'French', 'One of the favorites with stars like Mbappe, Griezmann and Camavinga. France reached the 2022 World Cup final and will be hungry to go one better in 2026.', '2022 World Cup Runners Up, 1998 Champions', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Brazil', 'World Cup 2026', 'Brazilian', 'The most successful World Cup nation with 5 titles. Brazil will look to end their long wait for a sixth title in 2026 with Vinicius Jr leading the attack.', '5x World Cup Champions', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('England', 'World Cup 2026', 'English', 'England reached the Euro 2024 final and will be among the favorites in 2026. Led by Harry Kane and Jude Bellingham, they are hungry for their second ever World Cup.', 'Euro 2024 Finalists, 1966 World Cup Winners', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Spain', 'World Cup 2026', 'Spanish', 'Euro 2024 Champions and one of the most technically gifted teams in the world. Spain will be strong favorites for the 2026 World Cup.', 'Euro 2024 Champions, 2010 World Cup Winners', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Germany', 'World Cup 2026', 'German', 'Germany will host Euro 2024 and are always dangerous at World Cups. With young talent emerging they could challenge for the 2026 title.', '4x World Cup Winners', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Portugal', 'World Cup 2026', 'Portuguese', 'Led by Cristiano Ronaldo who is desperate to win his first World Cup before retiring. Portugal have exciting young talent alongside their legendary captain.', 'Euro 2016 Champions', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Netherlands', 'World Cup 2026', 'Dutch', 'The Netherlands reached the 2022 World Cup quarterfinals and have exciting talent in Virgil van Dijk and Cody Gakpo. A dangerous dark horse for 2026.', '2022 World Cup Quarterfinalists', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Italy', 'World Cup 2026', 'Italian', 'The 2006 World Cup winners failed to qualify in 2018 and 2022. Italy will be desperate to return to the World Cup stage and prove themselves in 2026.', '4x World Cup Winners, 2020 Euro Champions', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Belgium', 'World Cup 2026', 'Belgian', 'Belgium''s golden generation featuring De Bruyne and Lukaku may have one last shot at glory in 2026. Ranked among the top teams in the world for years.', 'FIFA World Ranking Top 5', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jamal Musiala', 'Football', 'German', 'Jamal Musiala is one of the most talented young players in world football, playing for Bayern Munich and Germany. Born in Stuttgart with English and Nigerian heritage, Musiala chose to represent Germany and has become one of their most important players, known for his dribbling ability, technical skill and goalscoring.', 'Bundesliga Champion, German national team star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Pedri', 'Football', 'Spanish', 'Pedri is one of the most gifted midfielders of his generation, playing for Barcelona and Spain. He won the Golden Boy award in 2021 and was a key part of Spain''s Euro 2024 winning squad, known for his vision, passing and ability to control the tempo of any game.', 'Euro 2024 Winner, Golden Boy 2021', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Bukayo Saka', 'Football', 'English', 'Bukayo Saka is Arsenal''s most important player and one of England''s brightest stars. The versatile winger has been Arsenal''s player of the season multiple times and is known for his direct running, creativity and ability to score and assist at the highest level.', 'Arsenal key player, England national team star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Florian Wirtz', 'Football', 'German', 'Florian Wirtz is considered one of the most exciting young talents in European football, playing for Bayer Leverkusen and Germany. He was instrumental in Leverkusen''s historic unbeaten Bundesliga title winning season in 2024, showcasing his incredible creativity and technical ability.', 'Bundesliga Champion 2024 with Leverkusen', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Kyrie Irving', 'Basketball', 'American', 'Kyrie Irving is one of the most skillful ball handlers in NBA history, known for his incredible footwork and ability to score from anywhere on the court. He won an NBA Championship with LeBron James and the Cleveland Cavaliers in 2016, delivering one of the greatest performances in Finals history.', 'NBA Champion 2016, 7x All Star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Paul George', 'Basketball', 'American', 'Paul George is one of the most versatile two way players in the NBA, capable of guarding the best players on defense while scoring efficiently on offense. Known as PG-13, he has been one of the most consistent stars in the league for over a decade.', '9x All Star, NBA All Defensive Team', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Trae Young', 'Basketball', 'American', 'Trae Young is the Atlanta Hawks superstar point guard and one of the most exciting offensive players in the NBA. Known for his deep three point shooting and incredible passing ability, Young led the Hawks to the Eastern Conference Finals in 2021 in one of the greatest playoff runs in recent memory.', 'NBA All Star, Eastern Conference Finals 2021', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Sandro Mamukelashvili', 'Basketball', 'Georgian', 'Sandro Mamukelashvili is a Georgian NBA forward who has played for the Milwaukee Bucks and San Antonio Spurs. He is one of Georgia''s most successful basketball exports and a role model for young Georgian basketball players dreaming of reaching the NBA.', 'NBA player, Georgian national team star', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Goga Bitadze', 'Basketball', 'Georgian', 'Goga Bitadze is a Georgian NBA center who plays for the Orlando Magic. Known for his shot blocking, defensive presence and developing offensive game, Bitadze is one of Georgia''s proudest basketball achievements and represents his country with great pride at every opportunity.', 'NBA player, Orlando Magic center, Georgian national hero', true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Fernando Alonso', 'Formula 1', 'Spanish', 'Fernando Alonso is one of the greatest Formula 1 drivers of all time, winning two World Championships with Renault in 2005 and 2006. Still competing well into his 40s, Alonso is renowned for his incredible racecraft, tire management and ability to extract maximum performance from any car.', '2x Formula 1 World Champion 2005 and 2006', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('George Russell', 'Formula 1', 'British', 'George Russell is Mercedes'' lead driver and one of the most promising talents in Formula 1. Known as Mr Saturday for his exceptional qualifying performances, Russell won his first Formula 1 race at the 2022 Brazilian Grand Prix and is considered a future World Champion.', 'Formula 1 race winner, Mercedes lead driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Carlos Sainz Jr.', 'Formula 1', 'Spanish', 'Carlos Sainz Jr. is one of the most consistent and intelligent drivers in Formula 1. Son of rally legend Carlos Sainz, he won his first Grand Prix at the 2022 British Grand Prix with Ferrari and is known for his smooth driving style and exceptional racecraft throughout the season.', 'Formula 1 race winner, Ferrari and Williams driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Sergio Pérez', 'Formula 1', 'Mexican', 'Sergio Perez, known as Checo, is Mexico''s greatest ever Formula 1 driver. He was Max Verstappen''s teammate at Red Bull Racing and won multiple races, becoming one of the most popular drivers on the grid and a national hero in Mexico ahead of the 2026 World Cup.', 'Multiple F1 race wins, Red Bull Racing driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Oscar Piastri', 'Formula 1', 'Australian', 'Oscar Piastri is one of the most exciting young talents in Formula 1, racing for McLaren. He won his first Formula 1 race in 2024 and quickly established himself as a genuine championship contender, with many experts predicting he will become a future World Champion.', 'Formula 1 race winner 2024, McLaren driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Pierre Gasly', 'Formula 1', 'French', 'Pierre Gasly is one of the most experienced midfield drivers in Formula 1, racing for Alpine. He won a stunning victory at the 2020 Italian Grand Prix with AlphaTauri in one of the most emotional wins in recent Formula 1 history, beating the odds in dramatic fashion.', 'Formula 1 race winner, 2020 Italian Grand Prix', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Esteban Ocon', 'Formula 1', 'French', 'Esteban Ocon is a French Formula 1 driver who scored a memorable victory at the 2021 Hungarian Grand Prix. Known for his aggressive defending and consistent performances in the midfield, Ocon has established himself as a solid Formula 1 driver across multiple seasons.', 'Formula 1 race winner, 2021 Hungarian Grand Prix', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Valtteri Bottas', 'Formula 1', 'Finnish', 'Valtteri Bottas is a Finnish Formula 1 driver who spent several seasons as Lewis Hamilton''s teammate at Mercedes, winning multiple races and contributing to constructors championships. Known for his raw speed and dedication, Bottas is one of Finland''s finest motorsport exports.', 'Multiple F1 race wins, Mercedes constructors champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Daniel Ricciardo', 'Formula 1', 'Australian', 'Daniel Ricciardo is one of the most charismatic and popular drivers in Formula 1 history. Known for his trademark shoey celebration and brilliant overtaking ability, Ricciardo won eight Formula 1 races including a stunning victory at the 2021 Italian Grand Prix with McLaren.', '8x Formula 1 race winner, fan favorite', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Yuki Tsunoda', 'Formula 1', 'Japanese', 'Yuki Tsunoda is Japan''s most successful current Formula 1 driver, racing for RB. Known for his aggressive driving style and radio messages, Tsunoda has grown significantly as a driver and represents a new generation of Japanese talent pushing into Formula 1.', 'Formula 1 driver, Japan''s top F1 talent', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lance Stroll', 'Formula 1', 'Canadian', 'Lance Stroll is a Canadian Formula 1 driver racing for Aston Martin. He scored his first podium at the 2017 Azerbaijan Grand Prix as a rookie and has continued to develop as a driver, representing Canada on the global Formula 1 stage with growing confidence.', 'Formula 1 podium finisher, Aston Martin driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alex Albon', 'Formula 1', 'Thai', 'Alex Albon is a Thai-British Formula 1 driver racing for Williams. He previously drove for Red Bull Racing and has shown impressive pace throughout his career, becoming a fan favorite for his positive attitude and determination to succeed at the highest level.', 'Former Red Bull driver, Williams F1 driver', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Daniil Medvedev', 'Tennis', 'Russian', 'Daniil Medvedev is one of the best tennis players in the world, reaching the world number one ranking and winning the US Open in 2021. Known for his unique playing style, exceptional defense and ability to grind out victories against the best players in the world.', 'US Open Champion 2021, World No.1', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alexander Zverev', 'Tennis', 'German', 'Alexander Zverev is Germany''s best tennis player and one of the top players in the world. He won Olympic gold at the Tokyo 2020 Games and has reached multiple Grand Slam finals, known for his powerful serve and forehand that can dominate any opponent.', 'Olympic Gold Tokyo 2020, Multiple ATP Masters titles', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Stefanos Tsitsipas', 'Tennis', 'Greek', 'Stefanos Tsitsipas is Greece''s greatest ever tennis player and a consistent top five player in the world. He reached the French Open final in 2021 and has won multiple ATP Masters titles, known for his elegant one handed backhand and passionate playing style.', 'French Open Finalist 2021, ATP Finals Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Holger Rune', 'Tennis', 'Danish', 'Holger Rune is one of the most exciting young talents in tennis, representing Denmark at the highest level. He won the Paris Masters in 2022 by defeating Novak Djokovic in the final and is known for his intense competitive spirit and powerful baseline game.', 'Paris Masters Champion 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Andrey Rublev', 'Tennis', 'Russian', 'Andrey Rublev is one of the most consistent players on the ATP Tour, known for his powerful forehand and aggressive baseline game. He has won multiple ATP titles and is a regular presence in the latter stages of Grand Slam tournaments throughout his career.', 'Multiple ATP titles, Top 10 player', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Casper Ruud', 'Tennis', 'Norwegian', 'Casper Ruud is Norway''s greatest ever tennis player, reaching the world number two ranking and appearing in multiple Grand Slam finals including the French Open and US Open. Known for his clay court expertise and consistent performances throughout the season.', '2x Grand Slam Finalist, World No.2', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Taylor Fritz', 'Tennis', 'American', 'Taylor Fritz is the top ranked American tennis player and one of the best servers in the game. He won the Indian Wells Masters in 2022 and has established himself as a consistent top ten player, representing the next generation of American tennis talent.', 'Indian Wells Masters Champion 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Nick Kyrgios', 'Tennis', 'Australian', 'Nick Kyrgios is one of the most naturally talented and entertaining players in tennis history. He reached the Wimbledon final in 2022 and is known for his extraordinary serve, unpredictable shot making and passionate personality that divides opinion but thrills fans worldwide.', 'Wimbledon Finalist 2022, Australian Open doubles champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Grigor Dimitrov', 'Tennis', 'Bulgarian', 'Grigor Dimitrov is Bulgaria''s greatest tennis player and a former world number three. Known as Baby Fed for his elegant playing style similar to Roger Federer, Dimitrov won the ATP Finals in 2017 and has been one of the most technically gifted players of his generation.', 'ATP Finals Champion 2017, World No.3', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Hubert Hurkacz', 'Tennis', 'Polish', 'Hubert Hurkacz is Poland''s best tennis player and one of the most dangerous players on the ATP Tour. He won the Miami Open and reached the Wimbledon semifinals in 2021, known for his powerful serve and net game that makes him a threat on all surfaces.', 'Miami Open Champion, Wimbledon Semifinalist', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alex de Minaur', 'Tennis', 'Australian', 'Alex de Minaur is Australia''s top ranked tennis player and one of the fastest movers on the tour. Known as Demon for his lightning quick feet and relentless defensive game, De Minaur has consistently improved his ranking and reached the Wimbledon quarterfinals in 2024.', 'Australia''s top player, Wimbledon quarterfinalist 2024', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Frances Tiafoe', 'Tennis', 'American', 'Frances Tiafoe is one of the most exciting American tennis players, known for his entertaining personality and powerful game. He reached the US Open semifinals in 2022, defeating Rafael Nadal along the way in one of the biggest upsets of that year, thrilling the home crowd.', 'US Open Semifinalist 2022, defeated Nadal', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Ben Shelton', 'Tennis', 'American', 'Ben Shelton is one of the most exciting young players in tennis, known for his massive left handed serve and aggressive style. He reached the US Open semifinals in 2023 and is considered one of the brightest prospects in American tennis for the coming years.', 'US Open Semifinalist 2023', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Karen Khachanov', 'Tennis', 'Russian', 'Karen Khachanov is a powerful Russian tennis player who reached the US Open final in 2022. Known for his big serve and heavy groundstrokes, Khachanov has been one of the most consistent performers in the top twenty for several years on the ATP Tour.', 'US Open Finalist 2022, Olympic Silver Medal', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lamar Jackson', 'NFL', 'American', 'Lamar Jackson is the most dynamic quarterback in NFL history, winning two MVP awards with the Baltimore Ravens. Known for his extraordinary running ability combined with his improved passing, Jackson revolutionized the quarterback position and is considered one of the most dangerous players in the entire league.', '2x NFL MVP, Baltimore Ravens franchise quarterback', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Justin Jefferson', 'NFL', 'American', 'Justin Jefferson is widely considered the best wide receiver in the NFL today. Playing for the Minnesota Vikings, Jefferson broke multiple receiving records in his first few seasons and won the NFL Offensive Player of the Year award, establishing himself as a generational talent at the position.', 'NFL Offensive Player of Year, Minnesota Vikings star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Christian McCaffrey', 'NFL', 'American', 'Christian McCaffrey is the most complete running back in the NFL, capable of running, catching and blocking at an elite level. Playing for the San Francisco 49ers, McCaffrey won the NFL Offensive Player of the Year award and is one of the highest paid non-quarterback players in league history.', 'NFL Offensive Player of Year, San Francisco 49ers star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Travis Kelce', 'NFL', 'American', 'Travis Kelce is the greatest tight end in NFL history, winning three Super Bowls with the Kansas City Chiefs alongside Patrick Mahomes. Known for his incredible route running, hands and clutch performances, Kelce has redefined what is possible at the tight end position throughout his legendary career.', '3x Super Bowl Champion, Greatest TE in NFL history', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Tyreek Hill', 'NFL', 'American', 'Tyreek Hill is the fastest wide receiver in NFL history, earning the nickname Cheetah for his extraordinary speed. He won a Super Bowl with the Kansas City Chiefs before moving to the Miami Dolphins, where he became the first player to record over 1,700 receiving yards in a single season.', 'Super Bowl Champion, NFL receiving yards record', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Micah Parsons', 'NFL', 'American', 'Micah Parsons is the most dominant defensive player of his generation, playing for the Dallas Cowboys. Known for his incredible versatility to play multiple positions, pass rushing ability and football intelligence, Parsons has been named to the Pro Bowl in every season of his career so far.', 'NFL Defensive Rookie of Year, Multiple Pro Bowl selections', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Aaron Donald', 'NFL', 'American', 'Aaron Donald is widely considered the greatest defensive player in NFL history. Playing for the Los Angeles Rams, he won three Defensive Player of the Year awards and a Super Bowl in 2022, dominating offensive linemen in a way that had never been seen before in professional football.', '3x NFL Defensive Player of Year, Super Bowl Champion 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jalen Hurts', 'NFL', 'American', 'Jalen Hurts is the franchise quarterback of the Philadelphia Eagles and one of the most dynamic players in the NFL. He led the Eagles to the Super Bowl in 2023 and is known for his dual threat ability to both run and pass at an elite level, winning the NFL MVP award.', 'NFL MVP, Super Bowl appearance with Eagles', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Tua Tagovailoa', 'NFL', 'American', 'Tua Tagovailoa is the Miami Dolphins quarterback known for his accuracy and quick release. He led the Dolphins to a 2022 playoff appearance and has developed into one of the most efficient passers in the league, showing resilience throughout his career despite facing significant injury challenges.', 'Miami Dolphins franchise quarterback, Pro Bowl selection', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Dak Prescott', 'NFL', 'American', 'Dak Prescott is the franchise quarterback of the Dallas Cowboys and one of the highest paid players in NFL history. Known for his leadership, accuracy and ability to perform under pressure, Prescott has been one of the most consistent quarterbacks in the league throughout his career.', 'Dallas Cowboys franchise quarterback, Pro Bowl selection', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alexander Volkanovski', 'MMA & UFC', 'Australian', 'Alexander Volkanovski is one of the greatest UFC Featherweight Champions of all time, successfully defending his title multiple times before losing it to Ilia Topuria. Known for his incredible wrestling, cardio and chin, Volkanovski is considered one of the best pound for pound fighters in UFC history.', 'Former UFC Featherweight Champion, Multiple title defenses', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Sean O''Malley', 'MMA & UFC', 'American', 'Sean O''Malley is the former UFC Bantamweight Champion known for his flashy striking and entertaining fighting style. Called Sugar, O''Malley became champion by stopping Aljamain Sterling and is one of the most popular and marketable fighters in the entire UFC roster.', 'Former UFC Bantamweight Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Leon Edwards', 'MMA & UFC', 'British', 'Leon Edwards is a British UFC Welterweight Champion who delivered one of the greatest comebacks in UFC history, knocking out Kamaru Usman with a head kick in the fifth round to win the title. Edwards is one of the most technically skilled welterweights in the sport.', 'UFC Welterweight Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Kamaru Usman', 'MMA & UFC', 'Nigerian', 'Kamaru Usman is the Nigerian Nightmare and one of the greatest welterweights in UFC history. He successfully defended the UFC Welterweight Championship five times, defeating every top contender in his division with his dominant wrestling and powerful striking combination.', 'Former UFC Welterweight Champion, 5 title defenses', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Israel Adesanya', 'MMA & UFC', 'Nigerian', 'Israel Adesanya is the Stylebender and one of the most technically gifted strikers in MMA history. The Nigerian-New Zealand fighter won the UFC Middleweight Championship and is known for his striking artistry, creativity and showmanship that has made him one of the sport''s biggest stars.', 'Former UFC Middleweight Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alex Pereira', 'MMA & UFC', 'Brazilian', 'Alex Pereira is the UFC Light Heavyweight Champion and one of the most feared strikers in combat sports. A former Glory Kickboxing world champion, Pereira has knocked out multiple UFC champions and is known for his devastating left hook that has finished some of the best fighters in the world.', 'UFC Light Heavyweight Champion, Former Kickboxing World Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Dricus du Plessis', 'MMA & UFC', 'South African', 'Dricus du Plessis is the UFC Middleweight Champion and South Africa''s greatest MMA fighter. Known as Stillknocks, du Plessis is known for his aggressive grappling and ability to finish fights, becoming champion by defeating Sean Strickland and Sean O''Malley in memorable bouts.', 'UFC Middleweight Champion, South Africa''s greatest MMA fighter', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Tom Aspinall', 'MMA & UFC', 'British', 'Tom Aspinall is the UFC Interim Heavyweight Champion and widely considered the most exciting heavyweight in MMA today. Known for his combination of exceptional grappling, striking and athleticism, the British fighter has finished every opponent he has faced in the first round of their contest.', 'UFC Interim Heavyweight Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Francis Ngannou', 'MMA & UFC', 'Cameroonian', 'Francis Ngannou is the hardest puncher ever recorded in scientific testing and a former UFC Heavyweight Champion. Born in Cameroon, Ngannou''s journey from poverty to the pinnacle of combat sports is one of the most inspiring stories in the history of the sport.', 'Former UFC Heavyweight Champion, Hardest puncher ever recorded', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Charles Oliveira', 'MMA & UFC', 'Brazilian', 'Charles Oliveira is a Brazilian UFC Lightweight Champion and the record holder for most submission victories in UFC history. Known as Do Bronx, Oliveira is one of the most dangerous submission artists in MMA and has shown incredible heart in coming back from adversity throughout his career.', 'Former UFC Lightweight Champion, Most UFC submission wins', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Dustin Poirier', 'MMA & UFC', 'American', 'Dustin Poirier is the Diamond and one of the most beloved fighters in UFC history. A former interim Lightweight Champion, Poirier defeated Conor McGregor twice and has been involved in multiple Fight of the Year candidates throughout his legendary career in the sport.', 'Former UFC Interim Lightweight Champion, Defeated McGregor twice', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Justin Gaethje', 'MMA & UFC', 'American', 'Justin Gaethje is the Highlight and one of the most exciting fighters in UFC history. Known for his brawling style and incredible chin, Gaethje won the BMF title and has been involved in multiple Fight of the Year performances, always delivering incredible entertainment for MMA fans worldwide.', 'UFC BMF Champion, Multiple Fight of the Year awards', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Max Holloway', 'MMA & UFC', 'American', 'Max Holloway is Blessed and one of the greatest UFC Featherweight Champions of all time. The Hawaiian fighter holds the record for most significant strikes landed in UFC history and delivered one of the greatest performances ever seen when he knocked out Justin Gaethje at UFC 300.', 'Former UFC Featherweight Champion, Most strikes in UFC history', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Petr Yan', 'MMA & UFC', 'Russian', 'Petr Yan is a former UFC Bantamweight Champion and one of the most technically skilled strikers in the division. Known as No Mercy, Yan is considered one of the best pure boxers in MMA and has wins over multiple UFC champions throughout his impressive career.', 'Former UFC Bantamweight Champion', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Beauden Barrett', 'Rugby', 'New Zealander', 'Beauden Barrett is a two time World Rugby Player of the Year and one of the greatest attacking fullbacks in rugby history. Playing for the All Blacks, Barrett is known for his electric pace, incredible footwork and ability to create tries from nothing with his instinctive running game.', '2x World Rugby Player of the Year, All Blacks legend', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Dan Carter', 'Rugby', 'New Zealander', 'Dan Carter is widely considered the greatest fly half in rugby history, winning three World Rugby Player of the Year awards and two Rugby World Cups with the All Blacks. Known for his flawless kicking, tactical brilliance and leadership, Carter is the benchmark for all fly halves.', '3x World Rugby Player of Year, 2x Rugby World Cup Winner', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Johnny Sexton', 'Rugby', 'Irish', 'Johnny Sexton is Ireland''s greatest ever rugby player, winning the World Rugby Player of the Year award in 2018 and leading Ireland to a historic Grand Slam and series win over New Zealand. Known for his outstanding kicking game, composure and leadership throughout his legendary career.', 'World Rugby Player of Year 2018, Ireland Grand Slam', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Owen Farrell', 'Rugby', 'English', 'Owen Farrell is England''s most capped fly half and one of the best goal kickers in rugby history. Son of rugby league legend Andy Farrell, Owen led England to multiple Six Nations titles and a Rugby World Cup final in 2019, known for his ice cold nerve under pressure.', 'England rugby captain, 2019 World Cup Finalist', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Cheslin Kolbe', 'Rugby', 'South African', 'Cheslin Kolbe is one of the most exciting players in world rugby, playing for the Springboks and scoring a famous try in the 2019 Rugby World Cup final against England. Despite his small size, Kolbe is unstoppable in the open field and has won two Rugby World Cup medals.', '2x Rugby World Cup Winner, 2019 Final try scorer', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Eben Etzebeth', 'Rugby', 'South African', 'Eben Etzebeth is one of the most dominant locks in rugby history, playing for South Africa and known as the enforcer of the Springboks pack. His physicality, line out ability and leadership in the forwards have been crucial to South Africa winning back to back Rugby World Cups.', '2x Rugby World Cup Winner, Springboks lock', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Maro Itoje', 'Rugby', 'English', 'Maro Itoje is widely considered the best lock in the world and England''s most important player. Known for his incredible work rate, stealing lineouts and inspirational leadership, Itoje is a constant thorn in the side of every opposition and a future England captain in waiting.', 'England lock, British and Irish Lions player', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Ardie Savea', 'Rugby', 'New Zealander', 'Ardie Savea is the All Blacks captain and one of the best number eights in rugby, known for his explosive ball carrying, work rate and leadership. He won the World Rugby Player of the Year award in 2023 and is considered the heartbeat of the New Zealand team.', 'World Rugby Player of Year 2023, All Blacks captain', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Finn Russell', 'Rugby', 'Scottish', 'Finn Russell is Scotland''s most creative player and one of the most unpredictable fly halves in world rugby. Known for his offloading, quick thinking and ability to make something from nothing, Russell plays for Bath and has been instrumental in Scotland''s recent improvement on the world stage.', 'Scotland''s greatest player, Bath Rugby star', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Antoine Hastoy', 'Rugby', 'French', 'Antoine Hastoy is one of the most promising fly halves in French rugby, known for his creative play and strong kicking game. He has been part of France''s exciting generation of players that reached the Rugby World Cup semifinals on home soil in 2023.', 'French Top 14 player, France national team', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Gregory Alldritt', 'Rugby', 'French', 'Gregory Alldritt is one of the best number eights in world rugby and a key player for France and La Rochelle. Known for his powerful ball carrying and work rate, Alldritt has won multiple European Champions Cup titles with La Rochelle and is a cornerstone of the French national team.', 'European Champions Cup Winner, France national team', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Handré Pollard', 'Rugby', 'South African', 'Handre Pollard is the Springboks fly half and one of the best kickers in rugby history. His accurate goal kicking was crucial to South Africa winning the 2019 Rugby World Cup final against England and he has been one of the most consistent performers in world rugby for many years.', '2x Rugby World Cup Winner, Springboks fly half', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Julian Savea', 'Rugby', 'New Zealander', 'Julian Savea is one of the greatest try scorers in All Blacks history, earning the nickname The Bus for his powerful running style that made him almost impossible to stop. He scored tries in the 2015 Rugby World Cup semifinals and is considered one of the best wingers of his generation.', 'Rugby World Cup Winner 2015, All Blacks try scoring legend', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Usain Bolt', 'Olympics', 'Jamaican', 'Usain Bolt is the fastest human being ever recorded and the greatest sprinter in Olympic history. Winning three consecutive 100m and 200m gold medals, Bolt set world records of 9.58 seconds for the 100m and 19.19 for the 200m that still stand today and may never be broken.', '8x Olympic Gold, World records 100m and 200m', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Carl Lewis', 'Olympics', 'American', 'Carl Lewis is one of the greatest Olympians of all time, winning nine Olympic gold medals in sprinting and long jump across four consecutive Olympic Games. His longevity, versatility and dominance in multiple events made him a true legend of the sport and an inspiration to generations of athletes.', '9x Olympic Gold, 4 consecutive Olympics', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Mark Spitz', 'Olympics', 'American', 'Mark Spitz set a remarkable record at the 1972 Munich Olympics by winning seven gold medals in seven events, setting a world record in each one. His achievement stood as the greatest individual Olympic performance until Michael Phelps surpassed it at the 2008 Beijing Games.', '9x Olympic Gold, 7 golds at 1972 Munich Olympics', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Nadia Comaneci', 'Olympics', 'Romanian', 'Nadia Comaneci made history at the 1976 Montreal Olympics by becoming the first gymnast ever to receive a perfect score of 10.0, doing so seven times throughout the competition. At just 14 years old, she captivated the entire world and changed gymnastics forever with her flawless performances.', 'First perfect 10 in gymnastics history, 5x Olympic Gold', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Allyson Felix', 'Olympics', 'American', 'Allyson Felix is the most decorated American track and field athlete in Olympic history, winning 11 Olympic medals across five Games. Known for her incredible longevity and consistency, Felix won her final gold medal at the Tokyo 2020 Olympics in the mixed 4x400m relay.', '11 Olympic Medals, Most decorated US track athlete', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Katie Ledecky', 'Olympics', 'American', 'Katie Ledecky is the greatest female distance swimmer in Olympic history, winning 10 Olympic medals including seven gold medals across multiple Games. She holds world records in multiple freestyle events and is considered one of the most dominant athletes of her generation in any sport.', '10 Olympic Medals, 7 Olympic Gold, Multiple world records', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Mo Farah', 'Olympics', 'British', 'Mo Farah is Britain''s greatest ever distance runner, winning four Olympic gold medals in the 5000m and 10000m at consecutive Games in London and Rio. Born in Somalia, Farah''s journey to becoming a British Olympic legend is one of the most inspiring stories in the history of athletics.', '4x Olympic Gold, 5000m and 10000m double twice', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Haile Gebrselassie', 'Olympics', 'Ethiopian', 'Haile Gebrselassie is one of the greatest distance runners of all time, winning two Olympic gold medals in the 10000m at Atlanta and Sydney. The Ethiopian legend set 27 world records during his career and is widely considered the greatest long distance runner in the history of athletics.', '2x Olympic Gold 10000m, 27 World Records', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Shelly-Ann Fraser-Pryce', 'Olympics', 'Jamaican', 'Shelly-Ann Fraser-Pryce is the Pocket Rocket and one of the greatest sprinters in Olympic history. The Jamaican legend has won five Olympic gold medals in the 100m across multiple Games and is known for her explosive starts, colorful hair and passionate celebrations that have made her one of the most recognizable athletes in the world.', '5x Olympic Gold, 100m world champion multiple times', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Elaine Thompson-Herah', 'Olympics', 'Jamaican', 'Elaine Thompson-Herah completed the sprint double at both the Rio 2016 and Tokyo 2020 Olympics, winning the 100m and 200m at consecutive Games. At Tokyo she set an Olympic record of 10.61 seconds in the 100m, cementing her status as one of the greatest female sprinters in history.', '6x Olympic Gold, Sprint double at 2016 and 2020 Olympics', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Croatia', 'World Cup 2026', 'Croatian', 'Croatia are one of the great overachievers in World Cup history, reaching the final in 2018 where they lost to France and finishing third in 2022. Led by Luka Modric for many years, Croatia punch well above their weight and will be dangerous opponents for any team in 2026.', '2018 World Cup Runners Up, 2022 Third Place', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Uruguay', 'World Cup 2026', 'Uruguayan', 'Uruguay are two time World Cup winners and one of South America''s most passionate football nations. Despite their small population, Uruguay regularly qualifies for the World Cup and produces world class players, with a proud footballing tradition dating back to the first ever World Cup in 1930.', '2x World Cup Winners 1930 and 1950', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Denmark', 'World Cup 2026', 'Danish', 'Denmark are a consistently solid European side known for their team spirit and organization. They reached the Euro 2020 semifinals in an emotional tournament following Christian Eriksen''s cardiac arrest, and have established themselves as genuine contenders for major tournaments in recent years.', 'Euro 2020 Semifinalists, consistent European contenders', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Switzerland', 'World Cup 2026', 'Swiss', 'Switzerland are one of the most reliable and consistent teams in international football, regularly qualifying for major tournaments and causing upsets against higher ranked opponents. Known for their tactical discipline and fighting spirit, Switzerland reached the quarterfinals of Euro 2021.', 'Euro 2020 Quarterfinalists, consistent World Cup qualifiers', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Japan', 'World Cup 2026', 'Japanese', 'Japan are the strongest team in Asian football, having won the AFC Asian Cup four times. At the 2022 World Cup in Qatar, Japan caused stunning upsets by defeating both Germany and Spain in the group stage before losing to Croatia on penalties in the round of sixteen.', 'Defeated Germany and Spain at 2022 World Cup, 4x AFC Asian Cup', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('South Korea', 'World Cup 2026', 'South Korean', 'South Korea are Asia''s second strongest footballing nation and famously reached the semifinals of the 2002 World Cup on home soil. In 2022 they advanced to the round of sixteen, and with stars like Son Heung-min leading the team, South Korea will be a dangerous side in 2026.', '2002 World Cup Semifinalists, Son Heung-min era', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Morocco', 'World Cup 2026', 'Moroccan', 'Morocco made history at the 2022 World Cup in Qatar by becoming the first African nation ever to reach the semifinals of a World Cup. Their passionate performances captured the hearts of fans worldwide and they will enter the 2026 tournament as one of the most exciting and dangerous teams.', 'First African semifinalists in World Cup history 2022', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Mexico', 'World Cup 2026', 'Mexican', 'Mexico are one of the most passionate football nations in the world and will be co-hosting the 2026 World Cup. Having appeared at every World Cup since 1994, Mexico will have incredible home support and will be desperate to go beyond the round of sixteen where they have been eliminated five consecutive times.', 'Co-host of 2026 World Cup, 16 World Cup appearances', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('United States', 'World Cup 2026', 'American', 'The United States will be co-hosting the 2026 World Cup and have a golden generation of players including Christian Pulisic, Tyler Adams and Ricardo Pepi. After qualifying from a group containing England, Wales and Iran in 2022, the USMNT are growing fast and home advantage could make them dangerous.', 'Co-host of 2026 World Cup, 2022 Round of 16', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Turkey', 'World Cup 2026', 'Turkish', 'Turkey are one of Europe''s most improved football nations, reaching the Euro 2024 quarterfinals and producing stars like Arda Guler who is making waves at Real Madrid. With a passionate fan base and emerging talent, Turkey will be looking to make an impact at the 2026 World Cup.', 'Euro 2024 Quarterfinalists, Arda Guler generation', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Roger Federer', 'Tennis', 'Swiss', 'Roger Federer is considered by many as the most elegant and graceful tennis player of all time. Winning 20 Grand Slam titles across his legendary career, Federer spent 310 weeks as world number one and is beloved worldwide for his artistry, sportsmanship and the effortless beauty of his playing style.', '20x Grand Slam Winner, 310 weeks World No.1 - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Rafael Nadal', 'Tennis', 'Spanish', 'Rafael Nadal is the King of Clay and one of the greatest competitors in tennis history. Winning 22 Grand Slam titles including a record 14 French Open titles, Nadal''s relentless fighting spirit, physical intensity and never say die attitude made him one of the most beloved champions in all of sport.', '22x Grand Slam Winner, 14x French Open Champion - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Pete Sampras', 'Tennis', 'American', 'Pete Sampras dominated men''s tennis throughout the 1990s, winning 14 Grand Slam titles and spending 286 weeks as world number one. Known for his powerful serve and clinical net game, Sampras won seven Wimbledon titles and was considered the greatest player of his era before Federer, Nadal and Djokovic emerged.', '14x Grand Slam Winner, 7x Wimbledon Champion - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jerry Rice', 'NFL', 'American', 'Jerry Rice is the greatest wide receiver in NFL history and arguably the greatest player ever to play the game. Holding records for career receptions, receiving yards and touchdowns that may never be broken, Rice won three Super Bowls with the San Francisco 49ers and redefined what was possible at the wide receiver position.', '3x Super Bowl Champion, NFL all time receiving records - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Joe Montana', 'NFL', 'American', 'Joe Montana is one of the greatest quarterbacks in NFL history, winning four Super Bowls with the San Francisco 49ers without ever throwing an interception in a Super Bowl game. Known as Joe Cool for his incredible composure under pressure, Montana is considered the gold standard for clutch quarterbacking.', '4x Super Bowl Champion, 3x Super Bowl MVP - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lawrence Taylor', 'NFL', 'American', 'Lawrence Taylor is widely considered the greatest defensive player in NFL history, revolutionizing the linebacker position with his explosive speed and pass rushing ability. Playing for the New York Giants, LT won two Super Bowls and the NFL MVP award, one of only two defensive players ever to win that honor.', '2x Super Bowl Champion, NFL MVP - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jim Brown', 'NFL', 'American', 'Jim Brown is considered by many experts as the greatest running back in NFL history, never missing a game in nine seasons and retiring at the peak of his powers. Playing for the Cleveland Browns, Brown combined size, speed and power in a way that had never been seen before and has rarely been matched since.', 'Cleveland Browns legend, Greatest RB ever - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Peyton Manning', 'NFL', 'American', 'Peyton Manning is one of the greatest quarterbacks in NFL history, winning two Super Bowls with two different teams and setting the single season touchdown record of 55 touchdowns in 2013. Known for his incredible football intelligence, audibles at the line of scrimmage and leadership that elevated everyone around him.', '2x Super Bowl Champion, 5x NFL MVP - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Barry Sanders', 'NFL', 'American', 'Barry Sanders is considered the most elusive runner in NFL history, dazzling defenders with his incredible footwork, balance and ability to make people miss in a phone booth. Playing for the Detroit Lions, Sanders rushed for over 15,000 career yards and retired at the peak of his powers in one of the most shocking retirements in sports history.', 'Detroit Lions legend, 10x Pro Bowl - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Michael Schumacher', 'Formula 1', 'German', 'Michael Schumacher is the most successful Formula 1 driver of his era, winning seven World Championships and holding records that stood until Lewis Hamilton equaled them. His five consecutive titles with Ferrari from 2000 to 2004 represented the most dominant period by any driver in the sport''s history.', '7x Formula 1 World Champion - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Ayrton Senna', 'Formula 1', 'Brazilian', 'Ayrton Senna is considered by many as the greatest Formula 1 driver of all time. The Brazilian maestro won three World Championships and 41 races before his tragic death at Imola in 1994. Known for his extraordinary wet weather driving, qualifying pace and spiritual connection to racing, Senna remains the most loved driver in Formula 1 history.', '3x Formula 1 World Champion, 41 race wins - LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Alain Prost', 'Formula 1', 'French', 'Alain Prost is one of the greatest Formula 1 drivers of all time, winning four World Championships and 51 races throughout his legendary career. Known as The Professor for his calculating and intelligent approach to racing, Prost was the perfect contrast to his great rival Ayrton Senna in one of Formula 1''s greatest ever rivalries.', '4x Formula 1 World Champion, 51 race wins - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Niki Lauda', 'Formula 1', 'Austrian', 'Niki Lauda is one of the bravest and most determined champions in Formula 1 history. After surviving a near fatal crash at the 1976 German Grand Prix that left him severely burned, Lauda returned to racing just six weeks later in an act of extraordinary courage, going on to win two more World Championships.', '3x Formula 1 World Champion, Incredible comeback story - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jesse Owens', 'Olympics', 'American', 'Jesse Owens delivered one of the most iconic performances in Olympic history at the 1936 Berlin Games, winning four gold medals in front of Adolf Hitler and defying Nazi ideology about racial superiority. His achievements in the 100m, 200m, long jump and 4x100m relay remain one of the greatest individual Olympic performances ever.', '4x Olympic Gold 1936 Berlin, Icon of courage - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Emil Zátopek', 'Olympics', 'Czech', 'Emil Zatopek is considered the greatest distance runner of all time, winning three gold medals at the 1952 Helsinki Olympics in the 5000m, 10000m and marathon, having never run a marathon before. Known as the Czech Locomotive, Zatopek revolutionized training methods and inspired generations of distance runners worldwide.', '4x Olympic Gold, 5000m 10000m Marathon triple 1952 - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Paavo Nurmi', 'Olympics', 'Finnish', 'Paavo Nurmi, known as the Flying Finn, is one of the greatest distance runners in Olympic history, winning nine gold medals across three Olympic Games in the 1920s. His dominance of middle and long distance running was so complete that he won five gold medals at the 1924 Paris Olympics alone in remarkable fashion.', '9x Olympic Gold, 5 golds at 1924 Paris Olympics - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Lasse Virén', 'Olympics', 'Finnish', 'Lasse Viren is one of the greatest champions in Olympic distance running history, winning the 5000m and 10000m double at both the 1972 Munich and 1976 Montreal Olympics. His ability to peak perfectly for the Olympics, even falling and recovering during the Munich 10000m before winning, made him one of the most legendary performers in Games history.', '4x Olympic Gold, 5000m 10000m double twice - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jackie Joyner-Kersee', 'Olympics', 'American', 'Jackie Joyner-Kersee is considered the greatest female athlete of all time by Sports Illustrated, winning three Olympic gold medals in the heptathlon and long jump. Her world record in the heptathlon set at the 1988 Seoul Olympics has stood for over 35 years, a testament to her extraordinary all round athletic ability.', '3x Olympic Gold, Heptathlon world record holder - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Florence Griffith-Joyner', 'Olympics', 'American', 'Florence Griffith-Joyner, known as Flo-Jo, is the fastest woman in history, setting world records of 10.49 seconds for the 100m and 21.34 for the 200m at the 1988 Seoul Olympics that still stand over 35 years later. Her combination of extraordinary speed, glamour and style made her one of the most iconic athletes in Olympic history.', '3x Olympic Gold 1988, 100m and 200m world records still standing - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Jonah Lomu', 'Rugby', 'New Zealander', 'Jonah Lomu is the most iconic player in rugby history, a giant winger who combined the size of a forward with the pace of a sprinter. His performances at the 1995 Rugby World Cup, where he destroyed England almost single handedly, changed rugby forever and made the sport globally famous. Lomu passed away in 2015 aged just 40.', 'Rugby World Cup Winner, Most iconic rugby player ever - LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Martin Johnson', 'Rugby', 'English', 'Martin Johnson is England''s greatest ever rugby player, captaining his country to World Cup glory in 2003 with Jonny Wilkinson''s famous drop goal in extra time. The imposing lock was known as the most intimidating player in world rugby and led by example with his physicality, commitment and uncompromising standards.', 'Rugby World Cup Winner 2003 as Captain - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Brian O''Driscoll', 'Rugby', 'Irish', 'Brian O''Driscoll is Ireland''s greatest ever rugby player and one of the best centres in the history of the game. Known as BOD, he won four Six Nations titles with Ireland including a Grand Slam in 2009 and was named the greatest player of the professional era by many rugby experts after a career spanning 15 incredible years.', '4x Six Nations Winner, Greatest centre in rugby history - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian) VALUES ('Serge Blanco', 'Rugby', 'French', 'Serge Blanco is considered the greatest attacking fullback in the history of rugby union and one of France''s most beloved sporting icons. Known for his flair, improvisation and incredible try scoring ability, Blanco epitomized French running rugby at its most beautiful and was a joy to watch throughout his legendary career.', 'France rugby legend, Greatest attacking fullback ever - RETIRED LEGEND', false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Shota Arveladze', 'Football', 'Georgian', 'Shota Arveladze is one of Georgia''s greatest ever strikers, having a successful career in the Netherlands with Ajax and Rangers in Scotland. Known for his clinical finishing and intelligent movement, Arveladze was a hero for the Georgian national team and later became a successful coach.', 'Ajax and Rangers striker, Georgian national team legend', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Temur Ketsbaia', 'Football', 'Georgian', 'Temur Ketsbaia is one of the most beloved Georgian footballers of all time, famous for his passionate goal celebration at Newcastle United where he kicked his shirt into the crowd. Known for his tenacious work rate and never say die attitude, Ketsbaia became a cult hero at Newcastle.', 'Newcastle United cult hero, Georgian national team captain', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Giorgi Kinkladze', 'Football', 'Georgian', 'Giorgi Kinkladze is considered one of the most naturally gifted players ever to come out of Georgia, dazzling Premier League fans with his incredible dribbling and skill at Manchester City in the 1990s. Despite City''s relegation struggles, Kinkladze was consistently named one of the best players in England.', 'Manchester City legend, Most gifted Georgian footballer of his era', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Mikhail Meskhi', 'Football', 'Georgian', 'Mikhail Meskhi was one of the greatest Soviet era footballers and a legend of Georgian football, playing for Dinamo Tbilisi and the Soviet national team. Known as one of the best wingers in the world during the 1960s, Meskhi dazzled fans with his incredible pace and trickery on the left wing.', 'Dinamo Tbilisi legend, Soviet national team star of the 1960s', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('David Kipiani', 'Football', 'Georgian', 'David Kipiani is widely considered the greatest Georgian footballer of all time, leading Dinamo Tbilisi to the UEFA Cup Winners Cup in 1981, the greatest achievement in Georgian club football history. A brilliant playmaker known for his vision and technical ability, Kipiani is a national icon in Georgia.', 'UEFA Cup Winners Cup 1981 with Dinamo Tbilisi, Greatest Georgian footballer ever', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Zaza Pachulia', 'Basketball', 'Georgian', 'Zaza Pachulia is Georgia''s most successful NBA player, spending 13 seasons in the league with teams including the Milwaukee Bucks, Atlanta Hawks, Dallas Mavericks, Golden State Warriors and Detroit Pistons. He won two NBA Championships with the Golden State Warriors in 2017 and 2018 and is a national hero in Georgia.', '2x NBA Champion with Golden State Warriors 2017 and 2018', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Tornike Shengelia', 'Basketball', 'Georgian', 'Tornike Shengelia is one of the greatest Georgian basketball players of all time, dominating European basketball with CSKA Moscow and Baskonia for over a decade. Known for his powerful drives to the basket and clutch performances, Shengelia is one of the most respected players in EuroLeague history.', 'EuroLeague Champion, One of the best European players of his generation', true, false);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Manuchar Markoishvili', 'Basketball', 'Georgian', 'Manuchar Markoishvili is a highly respected Georgian basketball player who had a successful career in European basketball leagues. A talented shooting guard known for his scoring ability and leadership on the court, Markoishvili represented Georgia with pride throughout his professional career.', 'Georgian national team star, European basketball professional', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Dudu Dadiani', 'Basketball', 'Georgian', 'Dudu Dadiani is a legendary figure in Georgian basketball, having represented Georgia at the highest levels of European competition. Known for his basketball intelligence and clutch performances for the Georgian national team, Dadiani is one of the most respected names in the history of Georgian basketball.', 'Georgian basketball legend, National team representative', true, true);
INSERT INTO athlete (name, sport, nationality, info, achievement, georgian, retired) VALUES ('Otar Korkia', 'Basketball', 'Georgian', 'Otar Korkia is one of the most celebrated Georgian basketball players, known for his skill and dedication to the sport. A proud representative of Georgian basketball on the European stage, Korkia helped raise the profile of Georgian basketball throughout his distinguished professional career.', 'Georgian national team player, European basketball career', true, true);